import { hasInjectionContext, inject } from "vue";
import {
  useHead as headCore,
  useHeadSafe as headSafe,
  headSymbol,
  useSeoMeta as seoMeta,
  useServerHead as serverHead,
  useServerHeadSafe as serverHeadSafe,
  useServerSeoMeta as serverSeoMeta
} from "@unhead/vue";
import { tryUseNuxtApp } from "#app/nuxt";
export function injectHead(nuxtApp) {
  const nuxt = nuxtApp || tryUseNuxtApp();
  return nuxt?.ssrContext?.head || nuxt?.runWithContext(() => {
    if (hasInjectionContext()) {
      return inject(headSymbol);
    }
  });
}
export function useHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headCore(input, { head, ...options });
  }
}
export function useHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return headSafe(input, { head, ...options });
  }
}
export function useSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return seoMeta(input, { head, ...options });
  }
}
export function useServerHead(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHead(input, { head, ...options });
  }
}
export function useServerHeadSafe(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverHeadSafe(input, { head, ...options });
  }
}
export function useServerSeoMeta(input, options = {}) {
  const head = injectHead(options.nuxt);
  if (head) {
    return serverSeoMeta(input, { head, ...options });
  }
}
<template>
  <div class="space-y-3">
    <div class="aspect-square bg-gray-100 rounded-xl overflow-hidden">
      <img :src="main" alt="Product" class="w-full h-full object-cover cursor-zoom-in" @click="zoom = true" />
    </div>
    <div class="grid grid-cols-4 gap-2">
      <img v-for="(img, i) in images" :key="i" :src="img.image_url"
        class="aspect-square object-cover rounded cursor-pointer border-2 transition"
        :class="main === img.image_url ? 'border-indigo-500' : 'border-transparent'"
        @click="main = img.image_url" />
    </div>
    <div v-if="zoom" class="fixed inset-0 bg-black/80 z-50 flex items-center justify-center" @click="zoom = false">
      <img :src="main" class="max-h-screen max-w-screen-md object-contain" />
    </div>
  </div>
</template>

<script setup lang="ts">
import type { ProductImage } from '~/types/models.types'
const props = defineProps<{ images: ProductImage[] }>()
const main = ref(props.images[0]?.image_url ?? '/placeholder.png')
const zoom = ref(false)
</script>
<template>
  <div class="space-y-4">
    <div v-for="attr in attrs" :key="attr.name">
      <p class="text-sm font-semibold mb-2 capitalize">{{ attr.name }}</p>
      <div class="flex flex-wrap gap-2">
        <button v-for="val in attr.values" :key="val" @click="select(attr.name, val)"
          class="px-3 py-1.5 text-sm border rounded-lg transition"
          :class="selected[attr.name] === val ? 'border-indigo-600 bg-indigo-50 text-indigo-700' : 'border-gray-300 hover:border-gray-400'">
          {{ val }}
        </button>
      </div>
    </div>
    <div v-if="matched" class="bg-indigo-50 rounded-lg p-3 text-sm">
      Biến thể: <strong>{{ matched.variant_name }}</strong>
      <span v-if="matched.price_override" class="ml-2 text-red-600 font-bold">
        {{ new Intl.NumberFormat('vi-VN',{style:'currency',currency:'VND'}).format(matched.price_override) }}
      </span>
    </div>
  </div>
</template>

<script setup lang="ts">
import type { Product, ProductVariant } from '~/types/models.types'
const props = defineProps<{ product: Product }>()
const emit  = defineEmits<{ select: [v: ProductVariant] }>()
const selected = ref<Record<string, string>>({})

const attrs = computed(() => {
  const map: Record<string, Set<string>> = {}
  props.product.productVariants?.forEach(v =>
    Object.entries(v.attributes ?? {}).forEach(([k, val]) => {
      if (!map[k]) map[k] = new Set()
      map[k].add(val)
    })
  )
  return Object.entries(map).map(([name, values]) => ({ name, values: [...values] }))
})

const matched = computed(() =>
  props.product.productVariants?.find(v =>
    Object.entries(selected.value).every(([k, val]) => v.attributes?.[k] === val)
  ) ?? null
)

const select = (name: string, val: string) => {
  selected.value[name] = val
  if (matched.value) emit('select', matched.value)
}
</script>
<template>
  <div v-if="stock > 0" class="flex items-center gap-2">
    <span class="text-sm" :class="stock > 10 ? 'text-green-600' : 'text-orange-500'">
      {{ stock > 10 ? 'Còn hàng' : `Còn ${stock} sản phẩm` }}
    </span>
    <div class="w-24 h-1.5 bg-gray-200 rounded-full overflow-hidden">
      <div class="h-full rounded-full transition-all" :class="stock > 10 ? 'bg-green-500' : 'bg-orange-400'"
        :style="{ width: `${Math.min(100, (stock / 20) * 100)}%` }" />
    </div>
  </div>
  <p v-else class="text-red-600 font-semibold text-sm">Hết hàng</p>
</template>

<script setup lang="ts">
defineProps<{ stock: number }>()
</script>
<template>
  <div v-if="product" class="max-w-7xl mx-auto px-4 py-8">
    <div class="grid grid-cols-1 md:grid-cols-2 gap-12">
      <ProductGallery :images="product.productImages ?? []" />
      <div class="space-y-5">
        <div>
          <h1 class="text-2xl font-bold">{{ product.name }}</h1>
          <p class="text-gray-400 text-sm mt-1">SKU: {{ product.sku }}</p>
        </div>
        <p class="text-3xl font-bold text-red-600">{{ formatPrice(product.price) }}</p>
        <ProductVariantSelector v-if="product.productVariants?.length" :product="product" @select="v => selectedVariant = v" />
        <ProductStockIndicator :stock="selectedVariant?.stock ?? product.available_stock ?? 0" />
        <div class="flex items-center gap-3">
          <span class="text-sm font-medium">Số lượng:</span>
          <div class="flex items-center border rounded-lg">
            <button @click="qty = Math.max(1, qty - 1)" class="px-3 py-2">−</button>
            <input v-model.number="qty" type="number" min="1" class="w-12 text-center border-0 py-2 focus:outline-none" />
            <button @click="qty++" class="px-3 py-2">+</button>
          </div>
        </div>
        <div class="flex gap-3">
          <button @click="addToCart" :disabled="cartStore.loading || !product.available_stock"
            class="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-semibold hover:bg-indigo-700 disabled:opacity-50">
            {{ !product.available_stock ? 'Hết hàng' : 'Thêm vào giỏ' }}
          </button>
        </div>
        <div v-if="product.productImages" class="border-t pt-5">
          <h3 class="font-semibold mb-2">Mô tả</h3>
          <p class="text-gray-600 text-sm">{{ product.description }}</p>
        </div>
      </div>
    </div>
    <div class="mt-16">
      <h2 class="text-xl font-bold mb-6">Sản phẩm liên quan</h2>
      <div class="grid grid-cols-2 md:grid-cols-4 gap-6">
        <ProductCard v-for="r in related?.data" :key="r.id" :product="r" />
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import type { ProductVariant } from '~/types/models.types'

const route      = useRoute()
const cartStore  = useCartStore()
const qty        = ref(1)
const selectedVariant = ref<ProductVariant | null>(null)

const { data: product } = await useAsyncData(`product-${route.params.id}`,
  () => useProductApi().getById(route.params.id as string)
)
const { data: related } = await useAsyncData(`related-${route.params.id}`,
  () => useProductApi().getRelated(route.params.id as string)
)

const formatPrice = (p: number) => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(p)

const addToCart = () => cartStore.addToCart(
  product.value!.id, qty.value, selectedVariant.value?.id
)

useSeoMeta({
  title: () => product.value?.name ?? '',
  description: () => product.value?.description ?? '',
})
</script>
